import{_ as e,c as t,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"附錄 | Clawdbot 教程","description":"Clawdbot 附錄章節：完整設定參考、Gateway WebSocket API 協議、部署選項和開發指南。","frontmatter":{"title":"附錄 | Clawdbot 教程","sidebarTitle":"設定、部署、開發實戰","subtitle":"附錄","description":"Clawdbot 附錄章節：完整設定參考、Gateway WebSocket API 協議、部署選項和開發指南。","tags":[],"order":340},"headers":[],"relativePath":"zh-tw/moltbot/moltbot/appendix/index.md","filePath":"zh-tw/moltbot/moltbot/appendix/index.md"}'),r={name:"zh-tw/moltbot/moltbot/appendix/index.md"};function i(n,a,s,h,c,d){return o(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="附錄" tabindex="-1">附錄 <a class="header-anchor" href="#附錄" aria-label="Permalink to &quot;附錄&quot;">​</a></h1><p>本章節提供了 Clawdbot 的高級參考文件和開發資源，包括完整的設定參考、Gateway WebSocket API 協議規格、部署選項和開發指南。</p><div class="info custom-block"><p class="custom-block-title">適用場景</p><p>本章節適合需要深入了解 Clawdbot 內部機制、進行高級設定、部署或參與開發的用戶。如果您剛開始使用，建議先完成 <a href="./../../start/getting-started/">快速開始</a> 章節。</p></div><h2 id="子頁面導航" tabindex="-1">子頁面導航 <a class="header-anchor" href="#子頁面導航" aria-label="Permalink to &quot;子頁面導航&quot;">​</a></h2><h3 id="完整設定參考" tabindex="-1"><a href="./config-reference/">完整設定參考</a> <a class="header-anchor" href="#完整設定參考" aria-label="Permalink to &quot;[完整設定參考](./config-reference/)&quot;">​</a></h3><p><strong>詳細設定檔參考</strong> - 涵蓋所有設定項、預設值和範例。查找 Gateway、Agent、渠道、工具等模組的完整設定說明。</p><h3 id="gateway-websocket-api-協議" tabindex="-1"><a href="./api-protocol/">Gateway WebSocket API 協議</a> <a class="header-anchor" href="#gateway-websocket-api-協議" aria-label="Permalink to &quot;[Gateway WebSocket API 協議](./api-protocol/)&quot;">​</a></h3><p><strong>協議規格文件</strong> - Gateway WebSocket 協議的完整規格，包括端點定義、訊息格式、認證方式和事件訂閱機制。適合需要自訂客戶端或整合 Gateway 的開發者。</p><h3 id="部署選項" tabindex="-1"><a href="./deployment/">部署選項</a> <a class="header-anchor" href="#部署選項" aria-label="Permalink to &quot;[部署選項](./deployment/)&quot;">​</a></h3><p><strong>部署方式指南</strong> - 不同平台的部署方式：本地安裝、Docker、VPS、Fly.io、Nix 等。了解如何在各種環境中執行 Clawdbot。</p><h3 id="開發指南" tabindex="-1"><a href="./development/">開發指南</a> <a class="header-anchor" href="#開發指南" aria-label="Permalink to &quot;[開發指南](./development/)&quot;">​</a></h3><p><strong>開發者文件</strong> - 從原始碼建置、外掛開發、測試和貢獻流程。學習如何參與 Clawdbot 專案開發，或撰寫自訂外掛。</p><h2 id="學習路徑建議" tabindex="-1">學習路徑建議 <a class="header-anchor" href="#學習路徑建議" aria-label="Permalink to &quot;學習路徑建議&quot;">​</a></h2><p>根據您的需求，選擇適合的學習路徑：</p><h3 id="設定與運維人員" tabindex="-1">設定與運維人員 <a class="header-anchor" href="#設定與運維人員" aria-label="Permalink to &quot;設定與運維人員&quot;">​</a></h3><ol><li>先閱讀 <a href="./config-reference/">完整設定參考</a> - 了解所有可設定項</li><li>參考 <a href="./deployment/">部署選項</a> - 選擇合適的部署方案</li><li>根據需要查閱 Gateway WebSocket API 文件進行整合</li></ol><h3 id="應用程式開發者" tabindex="-1">應用程式開發者 <a class="header-anchor" href="#應用程式開發者" aria-label="Permalink to &quot;應用程式開發者&quot;">​</a></h3><ol><li>閱讀 <a href="./api-protocol/">Gateway WebSocket API 協議</a> - 理解協議機制</li><li>查看 <a href="./config-reference/">完整設定參考</a> - 了解如何設定相關功能</li><li>參考協議範例建置客戶端</li></ol><h3 id="外掛-功能開發者" tabindex="-1">外掛/功能開發者 <a class="header-anchor" href="#外掛-功能開發者" aria-label="Permalink to &quot;外掛/功能開發者&quot;">​</a></h3><ol><li>閱讀 <a href="./development/">開發指南</a> - 了解開發環境和建置流程</li><li>深入 <a href="./api-protocol/">Gateway WebSocket API 協議</a> - 理解 Gateway 架構</li><li>參考 <a href="./config-reference/">完整設定參考</a> - 了解設定系統</li></ol><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前置知識</p><p>在深入本章節之前，建議您已完成以下內容：</p><ul><li>✅ 完成了 <a href="./../../start/getting-started/">快速開始</a></li><li>✅ 設定了至少一個渠道（如 <a href="./../../platforms/whatsapp/">WhatsApp</a> 或 <a href="./../../platforms/telegram/">Telegram</a>）</li><li>✅ 了解了基礎的 AI 模型設定（參見 <a href="./../../advanced/models-auth/">AI 模型與認證</a>）</li><li>✅ 對 JSON 設定檔和 TypeScript 有基本了解</li></ul></div><h2 id="下一步指引" tabindex="-1">下一步指引 <a class="header-anchor" href="#下一步指引" aria-label="Permalink to &quot;下一步指引&quot;">​</a></h2><p>完成本章節學習後，您可以：</p><ul><li><strong>進行高級設定</strong> - 參考 <a href="./config-reference/">完整設定參考</a> 客製化您的 Clawdbot</li><li><strong>部署到生產環境</strong> - 按照 <a href="./deployment/">部署選項</a> 選擇適合的部署方案</li><li><strong>開發自訂功能</strong> - 參考 <a href="./development/">開發指南</a> 撰寫外掛或貢獻程式碼</li><li><strong>深入學習其他功能</strong> - 探索 <a href="./../../advanced/">進階功能</a> 章節，如會話管理、工具系統等</li></ul><div class="tip custom-block"><p class="custom-block-title">尋找協助</p><p>如果您在使用過程中遇到問題，可以查閱 <a href="./../../faq/troubleshooting/">疑難排解</a> 取得常見問題的解決方案。</p></div>',26)])])}const f=e(r,[["render",i]]);export{b as __pageData,f as default};
